import json


class Payload(object):
    def __init__(self, command="ls"):
        self.command = command


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return json.dumps({"command": payload.command}).encode('utf-8')

from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST', 'GET'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    # Get data from the request body; fallback to a query parameter 'data' if body is empty
    yaml_data = request.get_data(as_text=True)
    if not yaml_data:
        yaml_data = request.args.get('data', '')

    if not yaml_data:
        return jsonify({"error": "No YAML data provided"}), 400

    try:
        # Use safe_load to prevent arbitrary code execution (CWE-502)
        parsed_data = yaml.safe_load(yaml_data)

        # Ensure the result is a type that can be serialized to JSON
        if parsed_data is None:
            return jsonify({})

        return jsonify(parsed_data)
    except yaml.YAMLError as e:
        return jsonify({"error": f"Invalid YAML: {str(e)}"}), 400
    except TypeError:
        return jsonify({"error": "YAML content must be a dictionary or list to be returned as JSON"}), 400
